# Compute similarity metrics
cand_text = candidates[0]['ayah_text']
cand_norm = normalize_ar(cand_text)
sub_norm = norm_target  # normalized full substring

def token_f1(a, b):
    atoks = a.split()
    btoks = b.split()
    aset = {}
    for t in atoks:
        aset[t] = aset.get(t,0)+1
    bset = {}
    for t in btoks:
        bset[t] = bset.get(t,0)+1
    # intersection count:
    inter = 0
    for t,c in aset.items():
        if t in bset:
            inter += min(c, bset[t])
    prec = inter / max(1, len(atoks))
    rec = inter / max(1, len(btoks))
    if prec+rec==0:
        return 0.0
    return 2*prec*rec/(prec+rec), prec, rec

def lcs_len(a, b):
    # compute longest common subsequence length (characters)
    # dynamic programming
    la, lb = len(a), len(b)
    # use optimized DP with two rows to avoid huge memory
    dp_prev = [0]*(lb+1)
    for i in range(1, la+1):
        dp = [0]*(lb+1)
        ai = a[i-1]
        for j in range(1, lb+1):
            if ai == b[j-1]:
                dp[j] = dp_prev[j-1] + 1
            else:
                dp[j] = dp[j-1] if dp[j-1] > dp_prev[j] else dp_prev[j]
        dp_prev = dp
    return dp_prev[lb]

